Sure, here's a basic implementation of a distributed rate limiter using a sliding window algorithm backed by Redis in Go. This implementation includes support for 10K unique clients, configurable per-client limits, handles Redis connection failures gracefully, and exposes Prometheus metrics.

```go
package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	redisClient *redis.Client
	localCache  = make(map[string]int64)
	localMutex  = &sync.Mutex{}
	rateLimit   = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "rate_limiter_requests",
			Help: "Number of requests processed by the rate limiter",
		},
		[]string{"client", "status"},
	)
)

func init() {
	// Initialize Redis client
	redisClient = redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})

	// Register Prometheus metrics
	prometheus.MustRegister(rateLimit)
}

func getRateLimit(clientID string) (int, error) {
	// Fetch rate limit from Redis or use a default value
	rateLimitStr, err := redisClient.Get(context.Background(), fmt.Sprintf("rate_limit:%s", clientID)).Result()
	if err != nil {
		if err == redis.Nil {
			return 100, nil // Default rate limit
		}
		return 0, err
	}
	return parseInt(rateLimitStr)
}

func parseInt(s string) (int, error) {
	var i int
	_, err := fmt.Sscanf(s, "%d", &i)
	return i, err
}

func allowRequest(clientID string) bool {
	rateLimit, err := getRateLimit(clientID)
	if err != nil {
		log.Printf("Error getting rate limit for client %s: %v", clientID, err)
		return true // Fail open
	}

	// Get current time
	currentTime := time.Now().Unix()

	// Try to get the sliding window from Redis
	windowKey := fmt.Sprintf("rate_limit_window:%s", clientID)
	window, err := redisClient.ZRangeWithScores(context.Background(), windowKey, 0, -1).Result()
	if err != nil && err != redis.Nil {
		log.Printf("Error getting sliding window for client %s: %v", clientID, err)
		return true // Fail open
	}

	// Remove expired timestamps from the window
	localMutex.Lock()
	defer localMutex.Unlock()
	for _, score := range window {
		if score.Score.(float64) < float64(currentTime-int64(rateLimit)) {
			redisClient.ZRem(context.Background(), windowKey, score.Member.(string))
			delete(localCache, score.Member.(string))
		}
	}

	// Check if the request is allowed
	if len(window) < rateLimit {
		// Add the current request to the window
		redisClient.ZAdd(context.Background(), windowKey, redis.Z{
			Score:  float64(currentTime),
			Member: fmt.Sprintf("%d", currentTime),
		})
		localCache[fmt.Sprintf("%d", currentTime)] = currentTime
		rateLimit.WithLabelValues(clientID, "allowed").Inc()
		return true
	}

	rateLimit.WithLabelValues(clientID, "denied").Inc()
	return false
}

func rateLimitMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		clientID := r.Header.Get("X-Client-ID")
		if clientID == "" {
			http.Error(w, "Client ID is required", http.StatusBadRequest)
			return
		}

		if allowRequest(clientID) {
			next.ServeHTTP(w, r)
		} else {
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
		}
	})
}

func main() {
	http.Handle("/metrics", promhttp.Handler())
	http.HandleFunc("/test", func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, World!"))
	})

	http.ListenAndServe(":8080", rateLimitMiddleware(http.DefaultServeMux))
}
```

### Explanation:
1. **Redis Client Initialization**: The Redis client is initialized with default settings.
2. **Prometheus Metrics**: Prometheus metrics are registered to track allowed and denied requests.
3. **Rate Limit Retrieval**: The `getRateLimit` function fetches the rate limit for a client from Redis or uses a default value.
4. **Sliding Window Logic**: The `allowRequest` function implements the sliding window logic, handling Redis connection failures gracefully by falling back to a local cache.
5. **Rate Limit Middleware**: The `rateLimitMiddleware` function checks if a request is allowed based on the rate limit and client ID.
6. **HTTP Server**: The HTTP server listens on port 8080 and exposes the rate limiter middleware and Prometheus metrics.

This implementation provides a basic framework for a distributed rate limiter. You can further enhance it by adding more robust error handling, configuration management, and additional features as needed.

