```go
package main

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
)

const (
	tokensPerMinute = 100
	bucketCapacity   = 100
)

var (
	redisClient *redis.Client
	inMemory    = make(map[string]*tokenBucket)
	inMemoryMu  sync.Mutex
)

type tokenBucket struct {
	tokens    int
	lastRefill time.Time
}

func newTokenBucket() *tokenBucket {
	return &tokenBucket{
		tokens:    bucketCapacity,
		lastRefill: time.Now(),
	}
}

func refillTokens(tb *tokenBucket) {
	now := time.Now()
	elapsed := now.Sub(tb.lastRefill)
	tb.lastRefill = now
	tb.tokens = min(tb.tokens+int(elapsed.Seconds())*tokensPerMinute/60, bucketCapacity)
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func rateLimiter(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		ip := r.RemoteAddr
		tb := getTokenBucket(ip)

		refillTokens(tb)
		if tb.tokens > 0 {
			tb.tokens--
			next.ServeHTTP(w, r)
		} else {
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
		}
	})
}

func getTokenBucket(ip string) *tokenBucket {
	inMemoryMu.Lock()
	defer inMemoryMu.Unlock()

	if tb, exists := inMemory[ip]; exists {
		return tb
	}

	// Try to get from Redis
	ctx := context.Background()
	key := fmt.Sprintf("rate-limit:%s", ip)
	tokens, err := redisClient.Get(ctx, key).Int()
	if err == redis.Nil {
		// Key does not exist in Redis, create a new token bucket
		tb := newTokenBucket()
		inMemory[ip] = tb
		return tb
	} else if err != nil {
		// Redis error, fallback to in-memory
		tb := newTokenBucket()
		inMemory[ip] = tb
		return tb
	}

	// Key exists in Redis
	tb := &tokenBucket{
		tokens:    tokens,
		lastRefill: time.Now(),
	}
	inMemory[ip] = tb
	return tb
}

func initRedis() {
	redisClient = redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})
}

func saveTokenBucketToRedis(ip string, tb *tokenBucket) {
	ctx := context.Background()
	key := fmt.Sprintf("rate-limit:%s", ip)
	redisClient.Set(ctx, key, tb.tokens, 0)
}

func main() {
	initRedis()

	r := chi.NewRouter()
	r.Use(middleware.Logger)
	r.Use(rateLimiter)

	r.Get("/", func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, World!"))
	})

	http.ListenAndServe(":8080", r)
}
```

### Explanation:
1. **Token Bucket Algorithm**: The `tokenBucket` struct holds the current number of tokens and the last refill time. The `refillTokens` function refills tokens based on the elapsed time.
2. **Redis Integration**: The `getTokenBucket` function tries to fetch the token bucket from Redis. If Redis is down or the key does not exist, it falls back to an in-memory bucket.
3. **Chi Middleware**: The `rateLimiter` function is the middleware that checks the token bucket for each request.
4. **Graceful Handling**: If Redis is down, the system falls back to an in-memory token bucket to ensure the rate limiter continues to function.

